// ── AI Compliance Checker ────────────────────────────────────
// Checks a listing against food-safety, allergen, and policy rules

const body = $json.body;
const listing = body.listing || body;

const flags = [];

// ── ALLERGEN RULES ───────────────────────────────────────────
const MAJOR_ALLERGENS = [
  'peanuts', 'tree nuts', 'milk', 'eggs', 'wheat', 'soy', 'fish',
  'shellfish', 'sesame', 'gluten', 'lactose', 'dairy'
];

const descLower = (listing.description || '').toLowerCase();
const titleLower = (listing.title || '').toLowerCase();
const allText = titleLower + ' ' + descLower;
const declaredAllergens = (listing.allergens || []).map(a => a.toLowerCase());

MAJOR_ALLERGENS.forEach(allergen => {
  if (allText.includes(allergen) && !declaredAllergens.includes(allergen)) {
    flags.push({
      rule: 'ALLERGEN_UNDECLARED',
      severity: 'High',
      field: 'allergens',
      message: `Allergen '${allergen}' appears in description but is not declared in the allergen list.`
    });
  }
});

if ((listing.vertical === 'Meal Kits' || listing.vertical === 'Food Delivery') && declaredAllergens.length === 0) {
  flags.push({
    rule: 'ALLERGEN_LIST_MISSING',
    severity: 'High',
    field: 'allergens',
    message: 'Food listings must include an allergen declaration, even if allergen-free.'
  });
}

// ── FOOD SAFETY RULES ────────────────────────────────────────
if (listing.vertical === 'Food Delivery' || listing.vertical === 'Meal Kits') {
  if (!listing.ingredients || listing.ingredients.length === 0) {
    flags.push({
      rule: 'INGREDIENTS_MISSING',
      severity: 'High',
      field: 'ingredients',
      message: 'Food and meal kit listings must include a full ingredient list.'
    });
  }

  const prohibitedTerms = ['raw meat', 'unpasteurised', 'raw milk', 'raw egg'];
  prohibitedTerms.forEach(term => {
    if (allText.includes(term)) {
      flags.push({
        rule: 'FOOD_SAFETY_RISK',
        severity: 'High',
        field: 'description',
        message: `Listing mentions '${term}' — food safety handling instructions are required.`
      });
    }
  });
}

// ── POLICY RULES ─────────────────────────────────────────────
if (!listing.title || listing.title.trim().length < 5) {
  flags.push({ rule: 'TITLE_TOO_SHORT', severity: 'Medium', field: 'title', message: 'Listing title must be at least 5 characters.' });
}

if (!listing.price || listing.price <= 0) {
  flags.push({ rule: 'PRICE_MISSING', severity: 'High', field: 'price', message: 'Listing must have a valid price greater than zero.' });
}

if (!listing.description || listing.description.trim().length < 20) {
  flags.push({ rule: 'DESCRIPTION_TOO_SHORT', severity: 'Medium', field: 'description', message: 'Listing description must be at least 20 characters.' });
}

const prohibitedPolicyTerms = ['guaranteed cure', 'clinically proven', 'FDA approved', 'lose weight fast'];
prohibitedPolicyTerms.forEach(term => {
  if (allText.includes(term.toLowerCase())) {
    flags.push({ rule: 'MISLEADING_CLAIM', severity: 'High', field: 'description', message: `Prohibited marketing claim detected: '${term}'.` });
  }
});

// ── RESULT ────────────────────────────────────────────────────
const highFlags = flags.filter(f => f.severity === 'High');
const status    = flags.length === 0 ? 'Passed' : highFlags.length > 0 ? 'Failed' : 'Flagged';

return [{
  json: {
    listing_id:   listing.id || null,
    seller_id:    listing.seller_id || null,
    check_type:   'pre-publish',
    status,
    flags,
    flag_count:   flags.length,
    high_count:   highFlags.length,
    checked_at:   new Date().toISOString(),
    listing_title: listing.title,
    vertical:     listing.vertical
  }
}];

const result = $node['🔍 Run Compliance Rules'].json;
const flagList = result.flags.map(f => `• [${f.severity}] ${f.rule}: ${f.message}`).join('\n');

return [{
  json: {
    response: {
      status: result.status,
      listing_title: result.listing_title,
      flag_count: result.flag_count,
      flags: result.flags,
      message: result.status === 'Failed'
        ? `Your listing '${result.listing_title}' has ${result.high_count} critical compliance issue(s) and cannot be published until resolved.`
        : `Your listing '${result.listing_title}' has ${result.flag_count} compliance warning(s). Please review before publishing.`,
      flag_summary: flagList
    }
  }
}];
